// Calculate Experiment Health Score (EHS)
const experiment = $node["Loop Each Experiment"].json;
const metrics = $node["Get Last 7 Days Metrics"].json || [];

if (!metrics || metrics.length === 0) {
  return [{json: {ehs: 0, experiment_id: experiment.id, triggers: []}}];
}

// Get latest metrics
const latestMetrics = metrics[0] || {};
const allMetrics = metrics;

// Calculate component scores
const calculateTrafficScore = () => {
  const dailyVisitors = latestMetrics.unique_visitors || 0;
  if (dailyVisitors === 0) return 0;
  if (dailyVisitors < 10) return 25;
  if (dailyVisitors < 50) return 50;
  if (dailyVisitors < 100) return 75;
  return 100;
};

const calculateEngagementScore = () => {
  const avgTime = latestMetrics.avg_time_on_page || 0;
  if (avgTime === 0) return 0;
  if (avgTime < 30) return 25;
  if (avgTime < 60) return 50;
  if (avgTime < 120) return 75;
  return 100;
};

const calculateConversionScore = () => {
  const visitors = latestMetrics.unique_visitors || 0;
  const conversions = (latestMetrics.signups || 0) + (latestMetrics.purchases || 0);
  if (visitors === 0 || conversions === 0) return 0;
  const cvr = (conversions / visitors) * 100;
  if (cvr < 1) return 25;
  if (cvr < 2) return 50;
  if (cvr < 5) return 75;
  return 100;
};

const calculateRoiScore = () => {
  const spend = experiment.budget_spent || 0;
  const revenue = experiment.total_revenue || 0;
  if (spend === 0) return 50;
  if (revenue === 0) return 0;
  const roi = revenue / spend;
  if (roi < 0.5) return 25;
  if (roi < 1) return 50;
  if (roi < 2) return 75;
  return 100;
};

// Calculate weighted EHS
const trafficScore = calculateTrafficScore();
const engagementScore = calculateEngagementScore();
const conversionScore = calculateConversionScore();
const roiScore = calculateRoiScore();

const ehs = Math.round(
  trafficScore * 0.20 +
  engagementScore * 0.25 +
  conversionScore * 0.30 +
  roiScore * 0.25
);

// Check kill triggers
const triggers = [];
const daysLive = experiment.days_live || 0;
const totalVisitors = allMetrics.reduce((sum, m) => sum + (m.unique_visitors || 0), 0);
const totalSpend = experiment.budget_spent || 0;
const totalRevenue = experiment.total_revenue || 0;

// GHOST TOWN
if (daysLive >= 7 && totalVisitors < 15 && totalSpend > 10) {
  triggers.push('GHOST_TOWN');
}

// LEAKY BUCKET
if (totalVisitors >= 100 && latestMetrics.signups === 0 && latestMetrics.purchases === 0) {
  triggers.push('LEAKY_BUCKET');
}

// BUDGET BLEED
if (totalSpend >= 50 && totalRevenue < 5) {
  triggers.push('BUDGET_BLEED');
}

// EHS FLATLINE (check last 3 days)
const last3Days = metrics.slice(0, 3);
if (last3Days.length === 3 && last3Days.every(m => (m.ehs || 0) < 20)) {
  triggers.push('EHS_FLATLINE');
}

// HARD DEADLINE
if (daysLive >= 14 && ehs < 40) {
  triggers.push('HARD_DEADLINE');
}

// Check scale triggers
const scaleTriggers = [];

// FIRST REVENUE
if (totalRevenue > 0 && !experiment.scaled) {
  scaleTriggers.push('FIRST_REVENUE');
}

// HIGH CONVERSION
if (totalVisitors >= 50) {
  const totalConversions = allMetrics.reduce((sum, m) => sum + (m.signups || 0) + (m.purchases || 0), 0);
  const cvr = (totalConversions / totalVisitors) * 100;
  if (cvr >= 5) {
    scaleTriggers.push('HIGH_CONVERSION');
  }
}

// POSITIVE ROI
if (totalRevenue > totalSpend && totalSpend > 20) {
  scaleTriggers.push('POSITIVE_ROI');
}

return [{
  json: {
    experiment_id: experiment.id,
    ehs: ehs,
    traffic_score: trafficScore,
    engagement_score: engagementScore,
    conversion_score: conversionScore,
    roi_score: roiScore,
    kill_triggers: triggers,
    scale_triggers: scaleTriggers,
    days_live: daysLive,
    total_visitors: totalVisitors,
    total_spend: totalSpend,
    total_revenue: totalRevenue
  }
}];
